Here is a complete example of a REST API endpoint for user registration using **Node.js** and **Express**. 

It includes the requested validations, collects all validation errors (so the user sees everything they need to fix at once), and returns standard HTTP status codes along with structured JSON error responses.

### The Code (`server.js`)

```javascript
const express = require('express');
const app = express();

// Middleware to parse JSON bodies
app.use(express.json());

app.post('/api/register', (req, res) => {
    const { email, password, age } = req.body;
    const errors = [];

    // 1. Check for missing fields
    if (!email || !password || age === undefined) {
        return res.status(400).json({
            code: "BAD_REQUEST",
            message: "Email, password, and age are required fields."
        });
    }

    // 2. Validate Email Format
    // Standard regex for basic email validation
    const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
    if (!emailRegex.test(email)) {
        errors.push({
            code: "INVALID_EMAIL",
            field: "email",
            message: "Please provide a valid email address."
        });
    }

    // 3. Validate Password Strength
    // (?=.*\d) -> at least one number
    // (?=.*[!@#$%^&*(),.?":{}|<>]) -> at least one special character
    // .{8,} -> at least 8 characters long
    const passwordRegex = /^(?=.*\d)(?=.*[!@#$%^&*(),.?":{}|<>]).{8,}$/;
    if (!passwordRegex.test(password)) {
        errors.push({
            code: "WEAK_PASSWORD",
            field: "password",
            message: "Password must be at least 8 characters long, contain at least one number, and one special character."
        });
    }

    // 4. Validate Age
    if (typeof age !== 'number' || age < 18) {
        errors.push({
            code: "UNDERAGE",
            field: "age",
            message: "You must be at least 18 years old to register."
        });
    }

    // 5. Return errors if any validation failed
    if (errors.length > 0) {
        return res.status(400).json({
            code: "VALIDATION_FAILED",
            message: "The provided data is invalid.",
            errors: errors
        });
    }

    // --- SUCCESS ---
    // In a real application, you would hash the password (e.g., using bcrypt) 
    // and save the user to a database here.

    return res.status(201).json({
        code: "USER_CREATED",
        message: "User registered successfully.",
        data: {
            email: email,
            age: age
        }
    });
});

// Start the server
const PORT = process.env.PORT || 3000;
app.listen(PORT, () => {
    console.log(`Server is running on port ${PORT}`);
});
```

