import React, { useState, useMemo } from 'react';

const UserTable = ({ users }) => {
  const [filterText, setFilterText] = useState('');
  const [sortConfig, setSortConfig] = useState({ key: null, direction: 'ascending' });

  // Handle sorting logic when a header is clicked
  const requestSort = (key) => {
    let direction = 'ascending';
    if (sortConfig.key === key && sortConfig.direction === 'ascending') {
      direction = 'descending';
    }
    setSortConfig({ key, direction });
  };

  // useMemo ensures we only recalculate when users, filterText, or sortConfig change
  const processedUsers = useMemo(() => {
    // 1. Filter by name
    let filteredData = users.filter((user) =>
      user.name.toLowerCase().includes(filterText.toLowerCase())
    );

    // 2. Sort the filtered data
    if (sortConfig.key !== null) {
      filteredData.sort((a, b) => {
        const aValue = a[sortConfig.key];
        const bValue = b[sortConfig.key];

        if (aValue < bValue) {
          return sortConfig.direction === 'ascending' ? -1 : 1;
        }
        if (aValue > bValue) {
          return sortConfig.direction === 'ascending' ? 1 : -1;
        }
        return 0;
      });
    }

    return filteredData;
  }, [users, filterText, sortConfig]);

  // Helper to show up/down arrows on the currently sorted column
  const getSortIndicator = (key) => {
    if (sortConfig.key === key) {
      return sortConfig.direction === 'ascending' ? ' ▲' : ' ▼';
    }
    return '';
  };

  return (
    <div style={{ fontFamily: 'sans-serif', maxWidth: '600px', margin: '0 auto' }}>
      {/* Filter Input */}
      <div style={{ marginBottom: '15px' }}>
        <input
          type="text"
          placeholder="Filter by name..."
          value={filterText}
          onChange={(e) => setFilterText(e.target.value)}
          style={{ padding: '8px', width: '100%', boxSizing: 'border-box' }}
        />
      </div>

      {/* Data Table */}
      <table style={{ width: '100%', borderCollapse: 'collapse' }}>
        <thead>
          <tr style={{ backgroundColor: '#f4f4f4', textAlign: 'left' }}>
            <th 
              onClick={() => requestSort('name')} 
              style={{ padding: '10px', borderBottom: '2px solid #ddd', cursor: 'pointer' }}
            >
              Name{getSortIndicator('name')}
            </th>
            <th 
              onClick={() => requestSort('email')} 
              style={{ padding: '10px', borderBottom: '2px solid #ddd', cursor: 'pointer' }}
            >
              Email{getSortIndicator('email')}
            </th>
            <th 
              onClick={() => requestSort('role')} 
              style={{ padding: '10px', borderBottom: '2px solid #ddd', cursor: 'pointer' }}
            >
              Role{getSortIndicator('role')}
            </th>
          </tr>
        </thead>
        <tbody>
          {processedUsers.length > 0 ? (
            processedUsers.map((user) => (
              <tr key={user.id} style={{ borderBottom: '1px solid #ddd' }}>
                <td style={{ padding: '10px' }}>{user.name}</td>
                <td style={{ padding: '10px' }}>{user.email}</td>
                <td style={{ padding: '10px' }}>{user.role}</td>
              </tr>
            ))
          ) : (
            <tr>
              <td colSpan="3" style={{ padding: '10px', textAlign: 'center' }}>
                No users found.
              </td>
            </tr>
          )}
        </tbody>
      </table>
    </div>
  );
};

export default UserTable;
```

