As a Staff Engineer, I've designed this component with the following principles in mind:
1. **Performance**: Filtering and sorting are wrapped in a `useMemo` hook. We filter *before* sorting to reduce the number of items the sorting algorithm needs to process.
2. **Accessibility (a11y)**: Interactive headers use semantic `<button>` elements inside `<th>` tags. We also utilize the `aria-sort` attribute to announce the current sort state to screen readers, and a linked `<label>` for the search input.
3. **Reusability**: The table accepts a `columns` configuration array, making it easy to reuse this component for different data shapes in the future without changing the internal logic.
4. **Robust Sorting**: String comparisons use `localeCompare` for accurate alphabetical sorting, and we handle potential `null` or `undefined` values gracefully.

### The Component (`UserTable.tsx`)

```tsx
import React, { useState, useMemo } from 'react';

export interface User {
  id: string | number;
  name: string;
  email: string;
  role: string;
  [key: string]: any;
}

export interface ColumnConfig<T> {
  key: keyof T;
  label: string;
  sortable?: boolean;
}

interface UserTableProps {
  users: User[];
  columns: ColumnConfig<User>[];
}

type SortDirection = 'asc' | 'desc';

interface SortConfig<T> {
  key: keyof T;
  direction: SortDirection;
}

export const UserTable: React.FC<UserTableProps> = ({ users, columns }) => {
  const [filterText, setFilterText] = useState('');
  const [sortConfig, setSortConfig] = useState<SortConfig<User> | null>(null);

  // Handle column header clicks
  const handleSort = (key: keyof User) => {
    setSortConfig((currentSort) => {
      if (currentSort && currentSort.key === key) {
        // Toggle direction if clicking the same column
        return {
          key,
          direction: currentSort.direction === 'asc' ? 'desc' : 'asc',
        };
      }
      // Default to ascending when clicking a new column
      return { key, direction: 'asc' };
    });
  };

  // Memoized derived state: Filter first, then sort for optimal performance
  const processedUsers = useMemo(() => {
    // 1. Filter by name
    const lowerCaseFilter = filterText.toLowerCase().trim();
    const filtered = users.filter((user) =>
      user.name.toLowerCase().includes(lowerCaseFilter)
    );

    // 2. Sort the filtered results
    if (sortConfig !== null) {
      filtered.sort((a, b) => {
        const aValue = a[sortConfig.key];
        const bValue = b[sortConfig.key];

        // Handle null/undefined gracefully
        if (aValue == null) return 1;
        if (bValue == null) return -1;

        // Use localeCompare for strings, standard comparison for numbers/booleans
        if (typeof aValue === 'string' && typeof bValue === 'string') {
          return sortConfig.direction === 'asc'
            ? aValue.localeCompare(bValue)
            : bValue.localeCompare(aValue);
        }

        if (aValue < bValue) return sortConfig.direction === 'asc' ? -1 : 1;
        if (aValue > bValue) return sortConfig.direction === 'asc' ? 1 : -1;
        return 0;
      });
    }

    return filtered;
  }, [users, filterText, sortConfig]);

  return (
    <div className="user-table-container" style={{ fontFamily: 'system-ui, sans-serif' }}>
      {/* Filter Input */}
      <div style={{ marginBottom: '1rem' }}>
        <label 
          htmlFor="user-name-filter" 
          style={{ marginRight: '0.5rem', fontWeight: 'bold' }}
        >
          Filter by name:
        </label>
        <input
          id="user-name-filter"
          type="text"
          value={filterText}
          onChange={(e) => setFilterText(e.target.value)}
          placeholder="e.g. Jane Doe"
          style={{ padding: '0.5rem', borderRadius: '4px', border: '1px solid #ccc' }}
        />
      </div>

      {/* Data Table */}
      <table style={{ width: '100%', borderCollapse: 'collapse', textAlign: 'left' }}>
        <thead>
          <tr style={{ borderBottom: '2px solid #ddd' }}>
            {columns.map((col) => {
              const isSorted = sortConfig?.key === col.key;
              const ariaSort = isSorted
                ? sortConfig.direction === 'asc'
                  ? 'ascending'
                  : 'descending'
                : 'none';

              return (
                <th 
                  key={String(col.key)} 
                  aria-sort={ariaSort}
                  style={{ padding: '0.75rem' }}
                >
                  {col.sortable ? (
                    <button
                      onClick={() => handleSort(col.key)}
                      style={{
                        background: 'none',
                        border: 'none',
                        fontWeight: 'bold',
                        cursor: 'pointer',
                        padding: 0,
                        display: 'flex',
                        alignItems: 'center',
                        gap: '0.25rem',
                        font: 'inherit'
                      }}
                    >
                      {col.label}
                      {/* Visual Sort Indicator */}
                      {isSorted ? (
                        <span aria-hidden="true">
                          {sortConfig.direction === 'asc' ? '▲' : '▼'}
                        </span>
                      ) : (
                        <span aria-hidden="true" style={{ opacity: 0.3 }}>↕</span>
                      )}
                    </button>
                  ) : (
                    col.label
                  )}
                </th>
              );
            })}
          </tr>
        </thead>
        <tbody>
          {processedUsers.length > 0 ? (
            processedUsers.map((user) => (
              <tr key={user.id} style={{ borderBottom: '1px solid #eee' }}>
                {columns.map((col) => (
                  <td key={String(col.key)} style={{ padding: '0.75rem' }}>
                    {user[col.key]}
                  </td>
                ))}
              </tr>
            ))
          ) : (
            <tr>
              <td 
                colSpan={columns.length} 
                style={{ padding: '1rem', textAlign: 'center', color: '#666' }}
              >
                No users found matching "{filterText}".
              </td>
            </tr>
          )}
        </tbody>
      </table>
    </div>
  );
};
